              { type: "sword" as const, material: "steel", enchantment: 3, cursed: false },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      // Sword base premium: 100G
      // First insurance surcharge: +10% → 110G
      // Processing fee: +5G → 115G
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it.todo("should quote different item types with their respective base premiums");
    it.todo("should quote multiple items by summing their base premiums plus processing fee");
    it.todo("should quote components at 25G base premium each");
    it.todo("should quote a building block of 3 alike components at 60G instead of 75G");
    it.todo("should add 50% risk surcharge for cursed items");
    it.todo("should add 30% risk surcharge for highly enchanted items (enchantment >= 5)");
    it.todo("should apply 20% loyalty discount for long-standing customers (>= 2 years)");
    it.todo("should apply 10% initial assessment surcharge for first insurance");
    it.todo("should apply 15% discount on each contract after the first");
    it.todo("should round premiums up (ceiling) in MHPCO's favor");
  });

  describe("Processing a claim", () => {
    it.todo("should apply 100G deductible per damage event");
    it.todo("should cap total payout per policy at twice the insurance sum");
    it.todo("should reimburse damage to highly enchanted items (enchantment >= 8) at 50%");
    it.todo("should fully reimburse damage to dragon material items");
    it.todo("should round payouts down (floor) in MHPCO's favor");
  });

  describe("CLI integration", () => {
    it.todo("should process a scenario with a quote step and return results array");
  });
});

